function platesBetweenCandles(s, queries) {
    const n = s.length;
    const prefix = new Array(n).fill(0);
    let plates = 0;

    for (let i = 1; i < n; ++i) {
        prefix[i] = prefix[i - 1];
        if (s[i] === '*' && s[i - 1] === '|') plates++;
        prefix[i] += plates;
    }
    const res = [];

    for (const q of queries) {
        const left = q[0], right = q[1];
        res.push(prefix[right] - (left > 0 ? prefix[left - 1] : 0));
    }

    return res;
}
```

