import java.util.*;

class Solution {
    public List<Integer> platesBetweenCandles(String s, int[][] queries) {
        int n = s.length();
        int[] prefix = new int[n];
        int plates = 0;
        for (int i = 1; i < n; ++i) {
            prefix[i] = prefix[i - 1];
            if (s.charAt(i) == '*' && s.charAt(i - 1) == '|') {
                plates++;
            }
            prefix[i] += plates;
        }
        List<Integer> res = new ArrayList<>();
        for (int[] q : queries) {
            int left = q[0], right = q[1];
            res.add(prefix[right] - (left > 0 ? prefix[left - 1] : 0));
        }
        return res;
    }
}
```

